const fs = require('fs');
const QUEUE_FILE = '/home/ubuntu/yt_queue.json';

let jobs = [];
try {
  const raw = fs.readFileSync(QUEUE_FILE, 'utf8');
  const all = JSON.parse(raw);
  // 只返回 pending 状态的任务
  jobs = all.filter(j => j.status === 'pending');
  // 标记为 processing
  const updated = all.map(j =>
    j.status === 'pending' ? { ...j, status: 'processing', picked_at: new Date().toISOString() } : j
  );
  fs.writeFileSync(QUEUE_FILE, JSON.stringify(updated, null, 2));
} catch(e) {
  // 队列文件不存在或为空，正常
}

return [{ json: { jobs } }];

const fs = require('fs');
const QUEUE_FILE = '/home/ubuntu/yt_queue.json';
const body = $input.first().json.body || $input.first().json;

const { job_id, run_id, url, ok, raw_text, chars, language, error } = body;

// 从队列移除已完成任务
try {
  const all = JSON.parse(fs.readFileSync(QUEUE_FILE, 'utf8'));
  const updated = all.filter(j => j.job_id !== job_id);
  fs.writeFileSync(QUEUE_FILE, JSON.stringify(updated, null, 2));
} catch(e) {}

if (!ok) {
  return [{ json: { forwarded: false, reason: error || 'mac_failed' } }];
}

// 构建 openclaw handoff 格式
const items = [{
  source_type: 'youtube',
  source_url: url,
  title: `YouTube (本地转录)`,
  transcript: raw_text,
  language: language || 'zh+en',
  meta: { chars: chars || raw_text.length, method: 'mac_local_whisper' }
}];

return [{ json: { ok: true, run_id, items, need_materials: [], from_mac: true } }];
